async (params, browser) => {
  // Search sorted by price
  await browser.open(`https://www.aliexpress.com/w/wholesale-${params.query}.html?SortType=price_asc`)

  // Wait for results
  await browser.waitForSelector('[class*=\'search-item\'], [class*=\'product-card\']', 15000)

  await browser.wait(2000)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Extract and compare prices
  const comparison_data = await browser.evaluate(`const items = []; const cards = document.querySelectorAll('[class*="search-item-card"], [class*="product-card"], a[href*="/item/"]'); for (let i = 0; i < Math.min(cards.length, 20); i++) { const el = cards[i]; const titleEl = el.querySelector('h1, h3, [class*="title"]'); const priceEl = el.querySelector('[class*="price"]'); const ratingEl = el.querySelector('[class*="rating"], [class*="star"]'); const ordersEl = el.querySelector('[class*="sold"], [class*="orders"]'); const storeEl = el.querySelector('[class*="store"]'); const linkEl = el.tagName === 'A' ? el : el.querySelector('a[href*="/item/"]'); const shippingEl = el.querySelector('[class*="shipping"], [class*="delivery"]'); items.push({ title: titleEl ? titleEl.textContent.trim().substring(0, 200) : '', price: priceEl ? priceEl.textContent.trim() : '', rating: ratingEl ? ratingEl.textContent.trim() : '', orders: ordersEl ? ordersEl.textContent.trim() : '', store: storeEl ? storeEl.textContent.trim() : '', shipping: shippingEl ? shippingEl.textContent.trim() : '', url: linkEl ? linkEl.href : '' }); } const prices = items.map(function(item) { return parseFloat(item.price.replace(/[^0-9.]/g, '')) || 0; }).filter(function(p) { return p > 0; }); const avg = prices.length > 0 ? (prices.reduce(function(a,b){return a+b;},0)/prices.length).toFixed(2) : '0'; return { query: params.query, item_count: items.length, price_summary: { average: '$' + avg, lowest: prices.length > 0 ? '$' + Math.min.apply(null,prices).toFixed(2) : '$0', highest: prices.length > 0 ? '$' + Math.max.apply(null,prices).toFixed(2) : '$0' }, items: items }`)

  return comparison_data
}
